1	<script lang="ts">
2		// DotMeter v2 (the judge's hand-built take, for direct iteration with Jake).
3		// The design thesis: multiply-and-add should be VISIBLE, not narrated.
4		// Every bar is literally its two products stacked; the strip below shows
5		// the arithmetic for whichever candidate you select, live, to two decimals.
6	
7		// The two entries mean something: x is how loud, y is how fast.
8		const CANDIDATES = [
9			{ id: 'c1', name: 'Night Drive', angle: 20 },
10			{ id: 'c2', name: 'Glass Rain', angle: 70 },
11			{ id: 'c3', name: 'Slow Burn', angle: 110 },
12			{ id: 'c4', name: 'Static', angle: 160 }
13		];
14	
15		let challenge = $state<null | 'cheat' | 'short'>(null);
16		let solvedCheat = $state(false);
17		let solvedShort = $state(false);
18		const WHY = {
19			cheat:
20				'A song that is simply louder and faster everywhere piles up score without matching your mix. A raw meter overrates intense tracks, so a recommender built on it keeps pushing whatever is biggest.',
21			short:
22				'A quiet song that matches your mix exactly gets buried under bigger ones. Size is drowning direction, and fixing that is exactly where this lesson is headed.'
23		};
24		function startChallenge(kind: 'cheat' | 'short') {
25			// one click always re-arms: a solved card resets on first click,
26			// whether or not another challenge was active in between
27			if (kind === 'cheat' && (challenge === 'cheat' || solvedCheat)) solvedCheat = false;
28			if (kind === 'short' && (challenge === 'short' || solvedShort)) solvedShort = false;
29			challenge = kind;
30			probeAngle = 40;
31			lengthC1 = 1.0;
32			selected = 'c1';
33		}
34		$effect(() => {
35			if (challenge === 'cheat' && cheatActive) solvedCheat = true;
36			if (challenge === 'short' && shortChanged) solvedShort = true;
37		});
38	
39		let probeAngle = $state(40);
40		let lengthC1 = $state(1.0);
41		let selected = $state('c1');
42		let hovered = $state<string | null>(null);
43		let dragging = $state<'probe' | 'length' | null>(null);
44	
45		const rad = (d: number) => (d * Math.PI) / 180;
46	
47		const probe = $derived({ x: Math.cos(rad(probeAngle)), y: Math.sin(rad(probeAngle)) });
48	
49		const rows = $derived(
50			CANDIDATES.map((c) => {
51				const len = c.id === 'c1' ? lengthC1 : 1;
52				const x = len * Math.cos(rad(c.angle));
53				const y = len * Math.sin(rad(c.angle));
54				const px = probe.x * x; // the x-term product
55				const py = probe.y * y; // the y-term product
56				const score = px + py;
57				// r1 is the score at the SAME one-decimal precision the meter
58				// displays, so leader/tie judgments always match what's on screen.
59				const r1 = Number((Object.is(score, -0) ? 0 : score).toFixed(1));
60				return { ...c, len, x, y, px, py, score, r1 };
61			})
62		);
63	
64		const maxR1 = $derived(Math.max(...rows.map((r) => r.r1)));
65		const leaders = $derived(rows.filter((r) => r.r1 === maxR1).map((r) => r.id));
66		const tied = $derived(leaders.length > 1);
67		const sel = $derived(rows.find((r) => r.id === selected) ?? rows[0]);
68	
69		// The mirror lesson: c1 aims truest but is too short to win.
70		const shortChanged = $derived.by(() => {
71			const c1 = rows[0];
72			if (lengthC1 >= 0.95 || leaders.includes('c1')) return false;
73			return rows.every(
74				(r) =>
75					r.id === 'c1' ||
76					Math.abs(((r.angle - probeAngle + 540) % 360) - 180) >
77						Math.abs(((c1.angle - probeAngle + 540) % 360) - 180)
78			);
79		});
80	
81		// The overtake: c1 stretched AND outscoring a candidate that out-aligns it.
82		// Returns the most deserving victim (best-aligned beaten song) so the flag
83		// can name the exact pair instead of making a vague claim about the board.
84		const cheatVictim = $derived.by(() => {
85			const c1 = rows[0];
86			if (lengthC1 <= 1.05) return null;
87			const dist = (angle: number) => Math.abs(((angle - probeAngle + 540) % 360) - 180);
88			const beaten = rows.filter(
89				(r) => r.id !== 'c1' && dist(r.angle) < dist(c1.angle) && c1.r1 > r.r1
90			);
91			if (beaten.length === 0) return null;
92			return beaten.reduce((a, b) => (dist(a.angle) < dist(b.angle) ? a : b));
93		});
94		const cheatActive = $derived(cheatVictim !== null);
95		const leaderName = $derived(rows.find((r) => r.id === leaders[0])?.name ?? '');
96	
97		// --- Arena geometry (SVG units) ---
98		const S = 400; // viewBox square
99		const CX = S / 2;
100		const CY = S / 2;
101		const R = 92; // unit arrow length in px; 2.0 x R stays inside the frame
102		const pt = (x: number, y: number) => ({ px: CX + x * R, py: CY - y * R });
103	
104		function arrow(x: number, y: number) {
105			const tip = pt(x, y);
106			const ang = Math.atan2(CY - tip.py, tip.px - CX);
107			const L = Math.hypot(tip.px - CX, tip.py - CY);
108			const head = Math.max(7, Math.min(11, L * 0.09));
109			const back = { px: tip.px - head * Math.cos(ang), py: tip.py + head * Math.sin(ang) };
110			const left = {
111				px: back.px - head * 0.55 * Math.sin(ang),
112				py: back.py - head * 0.55 * Math.cos(ang)
113			};
114			const right = {
115				px: back.px + head * 0.55 * Math.sin(ang),
116				py: back.py + head * 0.55 * Math.cos(ang)
117			};
118			return {
119				shaft: { x1: CX, y1: CY, x2: back.px, y2: back.py },
120				head: `${tip.px},${tip.py} ${left.px},${left.py} ${right.px},${right.py}`
121			};
122		}
123	
124		// Tip label placement, in pixel space, not polar: push a touch past the
125		// tip along the arrow's own direction, then sideways, perpendicular to
126		// it. Candidates and the probe pass opposite `side` values, so even when
127		// the probe sweeps exactly onto a candidate's angle the two labels land
128		// on opposite sides of the shared line and never collide.
129		function tipLabel(x: number, y: number, side: 1 | -1) {
130			const tip = pt(x, y);
131			const dx = tip.px - CX;
132			const dy = tip.py - CY;
133			const mag = Math.hypot(dx, dy) || 1;
134			const ux = dx / mag;
135			const uy = dy / mag;
136			const perpx = -uy;
137			const perpy = ux;
138			const px = tip.px + ux * 12 + perpx * 17 * side;
139			const py = tip.py + uy * 12 + perpy * 17 * side;
140			return { px: cl(px), py: Math.min(Math.max(py, 14), S - 8) };
141		}
142	
143		let arenaEl = $state<SVGSVGElement | null>(null);
144	
145		function anglesFromEvent(e: PointerEvent) {
146			if (!arenaEl) return null;
147			const r = arenaEl.getBoundingClientRect();
148			const x = ((e.clientX - r.left) / r.width) * S - CX;
149			const y = CY - ((e.clientY - r.top) / r.height) * S;
150			return { angle: ((Math.atan2(y, x) * 180) / Math.PI + 360) % 360, dist: Math.hypot(x, y) / R };
151		}
152	
153		function onArenaPointer(e: PointerEvent) {
154			const a = anglesFromEvent(e);
155			if (!a || !dragging) return;
156			if (dragging === 'probe') probeAngle = Math.round(a.angle / 5) * 5 % 360;
157			else lengthC1 = Math.max(0.5, Math.min(2, Math.round(a.dist * 10) / 10));
158		}
159	
160		function startDrag(kind: 'probe' | 'length', e: PointerEvent) {
161			dragging = kind;
162			(e.currentTarget as Element).setPointerCapture(e.pointerId);
163		}
164	
165		function probeKeys(e: KeyboardEvent) {
166			let h = true;
167			if (e.key === 'ArrowRight' || e.key === 'ArrowUp') probeAngle = (probeAngle + 5) % 360;
168			else if (e.key === 'ArrowLeft' || e.key === 'ArrowDown') probeAngle = (probeAngle + 355) % 360;
169			else h = false;
170			if (h) e.preventDefault();
171		}
172	
173		function lengthKeys(e: KeyboardEvent) {
174			let h = true;
175			if (e.key === 'ArrowRight' || e.key === 'ArrowUp') lengthC1 = Math.min(2, Math.round((lengthC1 + 0.1) * 10) / 10);
176			else if (e.key === 'ArrowLeft' || e.key === 'ArrowDown') lengthC1 = Math.max(0.5, Math.round((lengthC1 - 0.1) * 10) / 10);
177			else h = false;
178			if (h) e.preventDefault();
179		}
180	
181		const f = (n: number) => (Object.is(n, -0) ? 0 : n).toFixed(2);
182		const cl = (v: number) => Math.min(Math.max(v, 24), S - 24);
183		const f1 = (n: number) => (Object.is(n, -0) ? 0 : n).toFixed(1);
184	
185		// Bar scale: scores live in [-2, 2] once c1 can stretch.
186		const BARMAX = 2.05;
187		const barH = 96;
188		const segH = (v: number) => (Math.abs(v) / BARMAX) * (barH / 2);
189	
190		const probeTip = $derived(pt(probe.x, probe.y));
191		const c1row = $derived(rows[0]);
192		const c1HandlePos = $derived(pt(c1row.x, c1row.y));
193	</script>
194	
195	<svelte:window onpointerup={() => (dragging = null)} />
196	
197	<div class="lab" data-interactive="dot-alignment">
198		<p class="invite">
199			Every song here is two numbers: how <em class="qw-loud">loud</em>, how <em class="qw-fast">fast</em>. So is your taste. Turn
200			the amber taste arrow and watch each song's match get <em>built</em>: the <span class="qw-loud">loud product</span> plus
201			the <span class="qw-fast">fast product</span>, stacked into one bar. Then grab Night Drive's round handle and change its size.
202		</p>
203		<div class="challenges">
204			<button class="chal" class:active={challenge === 'cheat' && !solvedCheat} class:done={solvedCheat} onclick={() => startChallenge('cheat')}>
205				<span class="chal-t mono">challenge 01</span>
206				<span class="chal-g">Make a worse match win</span>
207				{#if solvedCheat}
208					<span class="chal-s mono">✓ solved · click to retry</span>
209					<span class="chal-why">{WHY.cheat}</span>
210				{:else if challenge === 'cheat'}
211					<span class="chal-s mono live">in play…</span>
212				{/if}
213			</button>
214			<button class="chal" class:active={challenge === 'short' && !solvedShort} class:done={solvedShort} onclick={() => startChallenge('short')}>
215				<span class="chal-t mono">challenge 02</span>
216				<span class="chal-g">Make the truest song lose</span>
217				{#if solvedShort}
218					<span class="chal-s mono">✓ solved · click to retry</span>
219					<span class="chal-why">{WHY.short}</span>
220				{:else if challenge === 'short'}
221					<span class="chal-s mono live">in play…</span>
222				{/if}
223			</button>
224		</div>
225	
226		<div class="stage">
227			<div class="arena-wrap">
228				<svg
229					bind:this={arenaEl}
230					viewBox="0 0 {S} {S}"
231					class="arena"
232					onpointermove={onArenaPointer}
233					role="img"
234					aria-label="An amber probe arrow among four periwinkle candidate arrows; drag the probe tip to turn it, drag c1's tip to stretch it"
235				>
236					<!-- angle ring + ticks -->
237					<circle cx={CX} cy={CY} r={R} class="ring" />
238					{#each Array.from({ length: 12 }, (_, i) => i * 30) as t (t)}
239						<line
240							x1={CX + (R - 4) * Math.cos(rad(t))}
241							y1={CY - (R - 4) * Math.sin(rad(t))}
242							x2={CX + (R + 4) * Math.cos(rad(t))}
243							y2={CY - (R + 4) * Math.sin(rad(t))}
244							class="tick"
245						/>
246					{/each}
247					<!-- axes, whisper-quiet, but named: the two entries ARE qualities -->
248					<line x1={CX - R - 14} y1={CY} x2={CX + R + 14} y2={CY} class="axis" />
249					<line x1={CX} y1={CY - R - 14} x2={CX} y2={CY + R + 14} class="axis" />
250					<text x={CX + R + 18} y={CY - 6} class="axisq q-loud mono" aria-hidden="true">loud</text>
251					<text x={CX - 10} y={CY - R - 8} text-anchor="end" class="axisq q-fast mono" aria-hidden="true">fast</text>
252					<g class="legend" aria-hidden="true">
253						<line x1="16" y1="20" x2="34" y2="20" class="lg probe-stroke" />
254						<text x="40" y="24" class="lgt mono">your taste</text>
255						<line x1="16" y1="38" x2="34" y2="38" class="lg cand-stroke" />
256						<text x="40" y="42" class="lgt mono">songs</text>
257					</g>
258	
259					<!-- coordinates made visible: dashed drops for probe and selected -->
260					{#each [{ x: probe.x, y: probe.y, cls: 'p' }, { x: sel.x, y: sel.y, cls: 'c' }] as d (d.cls)}
261						{@const tip = pt(d.x, d.y)}
262						<line x1={tip.px} y1={tip.py} x2={tip.px} y2={CY} class="drop {d.cls}" />
263						<line x1={tip.px} y1={tip.py} x2={CX} y2={tip.py} class="drop {d.cls}" />
264						<text x={cl(tip.px)} y={CY + (d.cls === 'p' ? 13 : 25)} class="coord mono {d.cls}" aria-hidden="true">{f(d.x)}</text>
265						<text x={CX - (d.cls === 'p' ? 4 : 32)} y={cl(tip.py) - 3} class="coord mono {d.cls}" text-anchor="end" aria-hidden="true">{f(d.y)}</text>
266					{/each}
267	
268					<!-- candidates: each holds still, always named at its own tip -->
269					{#each rows as r (r.id)}
270						{@const a = arrow(r.x, r.y)}
271						{@const lp = tipLabel(r.x, r.y, -1)}
272						<g
273							class="cand"
274							class:sel={selected === r.id}
275							class:hov={hovered === r.id}
276							onpointerdown={() => (selected = r.id)}
277							role="button"
278							tabindex="-1"
279							aria-label={`select ${r.name}`}
280						>
281							<line {...{ x1: a.shaft.x1, y1: a.shaft.y1, x2: a.shaft.x2, y2: a.shaft.y2 }} class="shaft cand-stroke" />
282							<polygon points={a.head} class="cand-fill" />
283							<text x={lp.px} y={lp.py} class="lab song-lab halo" aria-hidden="true">{r.name}</text>
284						</g>
285					{/each}
286	
287					<!-- c1 length handle -->
288					<circle
289						cx={c1HandlePos.px}
290						cy={c1HandlePos.py}
291						r="9"
292						class="handle length-handle"
293						class:active={dragging === 'length'}
294						class:pulse={challenge !== null && !((challenge === 'cheat' && cheatActive) || (challenge === 'short' && shortChanged))}
295						onpointerdown={(e) => startDrag('length', e)}
296						onkeydown={lengthKeys}
297						role="slider"
298						tabindex="0"
299						data-control="length-c1"
300						aria-label="c1 length"
301						aria-valuemin="0.5"
302						aria-valuemax="2"
303						aria-valuenow={f1(lengthC1)}
304					/>
305	
306					<!-- probe on top: labeled on the object, offset to the opposite
307					     side from any candidate label so a direct sweep-through
308					     never buries either one -->
309					{#if true}
310						{@const a = arrow(probe.x, probe.y)}
311						{@const plab = tipLabel(probe.x, probe.y, 1)}
312						<line {...{ x1: a.shaft.x1, y1: a.shaft.y1, x2: a.shaft.x2, y2: a.shaft.y2 }} class="shaft probe-stroke" />
313						<polygon points={a.head} class="probe-fill" />
314						<text x={plab.px} y={plab.py} class="lab probe-lab halo" aria-hidden="true">your taste</text>
315					{/if}
316					<circle
317						cx={probeTip.px}
318						cy={probeTip.py}
319						r="11"
320						class="handle probe-handle"
321						class:active={dragging === 'probe'}
322						onpointerdown={(e) => startDrag('probe', e)}
323						onkeydown={probeKeys}
324						role="slider"
325						tabindex="0"
326						aria-label="probe angle in degrees"
327						aria-valuemin="0"
328						aria-valuemax="360"
329						aria-valuenow={Math.round(probeAngle)}
330					/>
331					<text x="14" y={S - 14} class="angle mono" aria-hidden="true">taste at {Math.round(probeAngle)}°</text>
332				</svg>
333			</div>
334	
335			<div class="meter">
336				{#each rows as r (r.id)}
337					<button
338						class="row"
339						class:leading={leaders.includes(r.id) && !tied}
340						class:sel={selected === r.id}
341						onmouseenter={() => (hovered = r.id)}
342						onmouseleave={() => (hovered = null)}
343						onclick={() => (selected = r.id)}
344						aria-label={`${r.id} score ${f1(r.score)}${leaders.includes(r.id) && !tied ? ', leading' : ''}`}
345					>
346						<span class="row-id">{r.name}</span>
347						<span class="bar" style="--h: {barH}px">
348							<span class="zero"></span>
349							<!-- x-term segment then y-term segment, stacked from the baseline -->
350							<span
351								class="seg segx"
352								class:neg={r.px < 0}
353								style="height: {segH(r.px)}px; bottom: {r.px >= 0 ? barH / 2 : barH / 2 - segH(r.px)}px"
354							></span>
355							<span
356								class="seg segy"
357								class:neg={r.py < 0}
358								style="height: {segH(r.py)}px; bottom: {r.py >= 0
359									? barH / 2 + (r.px > 0 ? segH(r.px) : 0)
360									: barH / 2 - segH(r.py) - (r.px < 0 ? segH(r.px) : 0)}px"
361							></span>
362						</span>
363						<span class="row-score mono">{f1(r.score)}</span>
364						{#if leaders.includes(r.id) && !tied}<span class="leads mono">leads</span>{/if}
365					</button>
366				{/each}
367				{#if tied}<span class="tie mono">tied</span>{/if}
368				{#if cheatVictim}
369					<span class="flag mono">⚑ {cheatVictim.name} matches your taste better, but Night Drive outscores it on size</span>
370				{:else if shortChanged}
371					<span class="flag short mono">⚑ Night Drive matches best, but {leaderName} wins on size</span>
372				{/if}
373			</div>
374		</div>
375		{#if challenge === null && cheatActive}
376			<p class="why">Why this matters: {WHY.cheat}</p>
377		{:else if challenge === null && shortChanged}
378			<p class="why">Why this matters: {WHY.short}</p>
379		{/if}
380		<p class="hint">
381			Click any bar or arrow to inspect it. The dashed lines are that arrow's two
382			entries (its loudness and its speed), the numbers the recipe multiplies.
383		</p>
384	
385		<div class="strip" aria-live="polite">
386			<span class="strip-lead">the whole recipe, live for <b>{sel.name}</b>:</span>
387			<span class="mono eq">
388				<span class="op qw-loud">loud</span>
389				<span class="probe-c">{f(probe.x)}</span>·<span class="cand-c">{f(sel.x)}</span>
390				<span class="op">+</span>
391				<span class="op qw-fast">fast</span>
392				<span class="probe-c">{f(probe.y)}</span>·<span class="cand-c">{f(sel.y)}</span>
393				<span class="op">=</span>
394				<span class="segx-c">{f(sel.px)}</span>
395				<span class="op">+</span>
396				<span class="segy-c">{f(sel.py)}</span>
397				<span class="op">=</span>
398				<span class="score-c">{f1(sel.score)}</span>
399			</span>
400			<span class="strip-note">
401				multiply the matched entries, add the products. The <span class="qw-loud">lilac slice</span>
402				of each bar is its loud product, the <span class="qw-fast">mint slice</span> its fast
403				product; stacked, they are the score.
404			</span>
405		</div>
406	</div>
407	
408	<style>
409		.lab {
410			max-width: 860px;
411			margin: 2rem auto;
412			padding: 1.4rem 1.6rem 1.2rem;
413			background: var(--color-surface);
414			border: 1px solid color-mix(in oklab, var(--color-text) 8%, transparent);
415			border-radius: 14px;
416		}
417		.invite {
418			margin: 0 0 1rem;
419			font-size: 0.98rem;
420			line-height: 1.5;
421			color: color-mix(in oklab, var(--color-text) 88%, transparent);
422		}
423		.invite em { color: var(--color-brand-mint); font-style: normal; }
424		.invite .qw-loud, .lab .invite .qw-loud { color: var(--data-params); font-style: normal; }
425		.invite .qw-fast, .lab .invite .qw-fast { color: color-mix(in oklab, var(--color-brand-mint) 85%, var(--color-text)); font-style: normal; }
426		.mono { font-family: var(--font-mono); }
427	
428		.stage { display: flex; flex-direction: column; gap: 0.8rem; align-items: center; }
429		.arena-wrap { width: 100%; max-width: 620px; }
430		.arena { width: 100%; height: auto; touch-action: none; display: block; }
431	
432		.ring { fill: none; stroke: color-mix(in oklab, var(--color-text) 10%, transparent); stroke-width: 1; }
433		.tick { stroke: color-mix(in oklab, var(--color-text) 14%, transparent); stroke-width: 1; }
434		.axis { stroke: color-mix(in oklab, var(--color-text) 7%, transparent); stroke-width: 1; }
435	
436		.shaft { stroke-width: 2.4; stroke-linecap: round; }
437		.cand-stroke { stroke: var(--data-observed); }
438		.cand-fill { fill: var(--data-observed); }
439		.probe-stroke { stroke: var(--data-heat); }
440		.probe-fill { fill: var(--data-heat); }
441		.cand { opacity: 0.82; cursor: pointer; transition: opacity var(--motion-min-ms) var(--ease-out-quint); }
442		.cand.sel { opacity: 1; }
