		if (e.key === 'ArrowRight' || e.key === 'ArrowUp') lengthC1 = Math.min(2, Math.round((lengthC1 + 0.1) * 10) / 10);
		else if (e.key === 'ArrowLeft' || e.key === 'ArrowDown') lengthC1 = Math.max(0.5, Math.round((lengthC1 - 0.1) * 10) / 10);
		else h = false;
		if (h) e.preventDefault();
